// Anti-loop + Human takeover + Message dedup
const item = $input.first().json;
const body = item.body || item;
const event = body.event;
const data = body.data || {};
const info = data.Info || {};

// Must be a Message event
if (event !== 'Message') return [];

// Not a group or broadcast
if (info.IsGroup === true) return [];
const chat = info.Chat || '';
if (chat.includes('@g.us') || chat.includes('@broadcast')) return [];

// =============================================
// MESSAGE ID DEDUP (prevents Stevo retry duplicates)
// =============================================
const messageId = info.ID || '';
if (messageId) {
  const staticData = $getWorkflowStaticData('global');
  if (!staticData.seenMsgIds) staticData.seenMsgIds = {};

  // Clean old entries (>5 min)
  const now = Date.now();
  const keys = Object.keys(staticData.seenMsgIds);
  for (const key of keys) {
    if (now - staticData.seenMsgIds[key] > 300000) {
      delete staticData.seenMsgIds[key];
    }
  }

  // Check if already seen
  if (staticData.seenMsgIds[messageId]) {
    return []; // Duplicate - skip
  }

  // Mark as seen
  staticData.seenMsgIds[messageId] = now;
}

// =============================================
// OUTGOING MESSAGE CLASSIFICATION
// =============================================
if (info.IsFromMe === true) {
  // Check IsBotInvoke to distinguish bot from human
  // IsBotInvoke=true → Bot sent via Stevo API → IGNORE
  // IsBotInvoke=false/undefined → Could be human typing in WhatsApp
  if (data.IsBotInvoke === true) {
    return []; // Bot echo - ignore completely
  }

  // Human sent message - flag for takeover
  const phone = chat.replace('@s.whatsapp.net', '').replace('@c.us', '');
  return [{
    json: {
      _action: 'human_takeover',
      _phone: phone,
      _chat_id: chat,
      _message_id: messageId,
      _human_name: info.PushName || 'Humano'
    }
  }];
}

// Incoming message from lead - pass through
return [{ json: item }];

// Extract message data from Stevo webhook
const item = $input.first().json;
const body = item.body || item;
const data = body.data || {};
const info = data.Info || {};
const msg = data.Message || {};

// Extract phone (remove @s.whatsapp.net)
const chatJid = info.Chat || '';
let phone = chatJid.replace('@s.whatsapp.net', '').replace('@c.us', '').replace('+', '');

// Normalize Brazilian mobile numbers
let phoneGHL = phone;
if (phone.startsWith('55') && phone.length === 12) {
  const ddd = phone.substring(2, 4);
  const number = phone.substring(4);
  phoneGHL = '55' + ddd + '9' + number;
}
phoneGHL = '+' + phoneGHL;

const name = info.PushName || '';

// Extract message text and media type
let text = '';
let mediaType = 'text';

const msgType = info.Type || '';
const mediaSubType = info.MediaType || '';

if (msg.conversation) {
  text = msg.conversation;
  mediaType = 'text';
} else if (msg.extendedTextMessage && msg.extendedTextMessage.text) {
  text = msg.extendedTextMessage.text;
  mediaType = 'text';
} else if (msgType === 'media' && (mediaSubType === 'ptt' || mediaSubType === 'audio')) {
  mediaType = 'audio';
  text = '';
} else if (msgType === 'media' && (msg.imageMessage || mediaSubType === 'image')) {
  mediaType = 'image';
  text = msg.imageMessage?.caption || '';
} else if (msgType === 'media' && (msg.documentMessage || mediaSubType === 'document')) {
  mediaType = 'document';
  text = msg.documentMessage?.title || msg.documentMessage?.fileName || '[Documento enviado]';
} else if (msgType === 'media' && (msg.videoMessage || mediaSubType === 'video')) {
  mediaType = 'video';
  text = msg.videoMessage?.caption || '[Vídeo enviado]';
} else if (msgType === 'media' && (msg.stickerMessage || mediaSubType === 'sticker')) {
  mediaType = 'sticker';
  text = '[Sticker enviado]';
} else {
  text = msg.conversation || '';
  if (!text && msg.extendedTextMessage) text = msg.extendedTextMessage.text || '';
  mediaType = 'text';
}

const messageId = info.ID || '';

// Build raw message object for Stevo download API
// Stevo needs: { key: {remoteJid, fromMe, id}, <mediaType>Message: {...} }
const rawMessage = {
  key: {
    remoteJid: chatJid,
    fromMe: false,
    id: messageId
  }
};
// Include the media message object (audioMessage, imageMessage, etc.)
if (msg.audioMessage) rawMessage.audioMessage = msg.audioMessage;
if (msg.imageMessage) rawMessage.imageMessage = msg.imageMessage;
if (msg.documentMessage) rawMessage.documentMessage = msg.documentMessage;
if (msg.videoMessage) rawMessage.videoMessage = msg.videoMessage;
if (msg.stickerMessage) rawMessage.stickerMessage = msg.stickerMessage;

return [{
  json: {
    phone, phoneGHL, name, text, mediaType, messageId,
    rawMessage,
    audioBase64: '',
    audioMimetype: msg.audioMessage?.mimetype || 'audio/ogg',
    imageBase64: '',
    ghl_api_key: item.ghl_api_key,
    ghl_location_id: item.ghl_location_id,
    ghl_pipeline_id: item.ghl_pipeline_id,
    stevo_server_url: item.stevo_server_url,
    stevo_instance: item.stevo_instance,
    stevo_api_key: item.stevo_api_key,
    supabase_url: item.supabase_url,
    supabase_key: item.supabase_key
  }
}];

// Get audio base64 - try multiple sources
const original = $('Extrair Dados').first().json;

// Source 1: Stevo webhook already includes base64 in Message
const webhookData = $('Webhook Stevo').first().json;
const webhookBase64 = webhookData?.body?.data?.Message?.base64 || '';

// Source 2: Download node result (fallback)
let downloadBase64 = '';
try {
  const downloadResult = $('Baixar Áudio Stevo').first().json;
  downloadBase64 = downloadResult?.base64 || '';
} catch(e) { /* download may have failed */ }

// Use whichever source has data
const audioBase64 = webhookBase64 || downloadBase64;

if (!audioBase64) {
  return [{ json: { ...original, text: '[Áudio recebido - não foi possível processar]', hasAudio: false } }];
}

// Get mimetype from audioMessage metadata
const audioMsg = webhookData?.body?.data?.Message?.audioMessage || {};
const mimetype = audioMsg.mimetype || 'audio/ogg; codecs=opus';

return [{
  json: { ...original, hasAudio: true },
  binary: {
    audio: {
      data: audioBase64,
      mimeType: mimetype.split(';')[0].trim(),
      fileName: 'audio.ogg'
    }
  }
}];

