const joinedMessage = messages.join(', ');

// Get config from earlier nodes
const extractData = $('Extrair Dados').first().json;

return [{
  json: {
    mensagem: joinedMessage,
    phone: extractData.phone,
    name: extractData.name,
    ghl_location_id: extractData.ghl_location_id,
    ghl_pipeline_id: extractData.ghl_pipeline_id,
    stevo_server_url: extractData.stevo_server_url,
    stevo_instance: extractData.stevo_instance,
    stevo_api_key: extractData.stevo_api_key
  },
  pairedItem: { item: 0 }
}];

