const output = $input.first().json.output || $input.first().json.text || '';
const phone = $('Extrair Dados').item.json.phone;
const config = {
  stevo_server_url: $('Extrair Dados').item.json.stevo_server_url,
  stevo_instance: $('Extrair Dados').item.json.stevo_instance,
  stevo_api_key: $('Extrair Dados').item.json.stevo_api_key
};

// Split by double newline
let messages = output.split(/\n\n+/).filter(m => m.trim());

// If no splits, send as single message
if (messages.length === 0) {
  messages = [output];
}

// Limit to max 5 messages
if (messages.length > 5) {
  messages = messages.slice(0, 5);
}

return messages.map(msg => ({
  json: {
    phone,
    message: msg.trim(),
    ...config
  }
}));

