// Compares message_id from "Buscar Última" (Supabase) with current execution
const ultimaMsg = $('Buscar Última').first().json;
const currentMsgId = $('Extrair Dados').first().json.messageId;

const ultimaMsgId = ultimaMsg ? ultimaMsg.message_id : null;

// No match = this is NOT the last message, STOP this execution
if (!ultimaMsgId || !currentMsgId || ultimaMsgId !== currentMsgId) {
  return [];
}

// Match = this IS the last message, continue
return [$input.first()];

// Join all pending messages into single text
const items = $input.all();
const messages = items.map(item => item.json.message).filter(m => m && m.trim());
const joinedMessage = messages.join(', ');

// Get config from earlier nodes
const extractData = $('Extrair Dados').first().json;

return [{
  json: {
    mensagem: joinedMessage,
    phone: extractData.phone,
    name: extractData.name,
    ghl_location_id: extractData.ghl_location_id,
    ghl_pipeline_id: extractData.ghl_pipeline_id,
    stevo_server_url: extractData.stevo_server_url,
    stevo_instance: extractData.stevo_instance,
    stevo_api_key: extractData.stevo_api_key
  },
  pairedItem: { item: 0 }
}];

// Split AI response into multiple messages
const output = $input.first().json.output || $input.first().json.text || '';
const phone = $('Extrair Dados').item.json.phone;
const config = {
  stevo_server_url: $('Extrair Dados').item.json.stevo_server_url,
  stevo_instance: $('Extrair Dados').item.json.stevo_instance,
  stevo_api_key: $('Extrair Dados').item.json.stevo_api_key
};

// Split by double newline
let messages = output.split(/\n\n+/).filter(m => m.trim());

// If no splits, send as single message
if (messages.length === 0) {
  messages = [output];
}

// Limit to max 5 messages
if (messages.length > 5) {
  messages = messages.slice(0, 5);
}

return messages.map(msg => ({
  json: {
    phone,
    message: msg.trim(),
    ...config
  }
}));

// BLACKLIST: Clara responde a TODOS, exceto contatos com tag de bloqueio
// Se contato NAO existe no GHL, Clara tambem responde (lead novo)
const contact = $('Verificar Contato').first().json.contact;
const extractData = $('Extrair Dados').first().json;

// Tags que BLOQUEIAM a Clara
const BLOCK_TAGS = [
  'ia-pausada',
  'atendimento-humano',
  'nao-ia',
  'cliente-ativo',
  'spam',
  'bloqueado'
];

// SEM CONTATO no GHL = RESPONDE (lead novo)

// Normalize phone for GHL search format
let _phoneGHL = (extractData.phone || '');
if (_phoneGHL.startsWith('55') && _phoneGHL.length === 12) {
  _phoneGHL = '+55' + _phoneGHL.substring(2, 4) + '9' + _phoneGHL.substring(4);
} else {
  _phoneGHL = '+' + _phoneGHL;
}
if (!contact) {
  return [{
    json: {
      ...extractData,
      ghl_contact_id: null,
      ghl_tags: [],
      ghl_contact_name: extractData.name || '',
      is_new_lead: true,
      ia_allowed: true,
      pairedItem: { item: 0 }
    }
  }];
}

const tags = (contact.tags || []).map(t => t.toLowerCase().trim());

// Block tags = NAO responde
const blocked = BLOCK_TAGS.some(bt => tags.includes(bt));
if (blocked) {
  return []; // BLOQUEADO por tag
}

// AUTORIZADO: Sem tag de bloqueio = Clara responde
return [{
  json: {
    ...extractData,
    ghl_contact_id: contact.id,
    ghl_tags: contact.tags || [],
    ghl_contact_name: contact.contactName || contact.firstName || '',
    is_new_lead: false,
    ia_allowed: true,
    pairedItem: { item: 0 }
  }
}];

// Extract phone for GHL contact lookup
// This node ONLY transforms data - no HTTP calls
const phone = $json._phone;
const chatId = $json._chat_id;
const humanName = $json._human_name;
const now = new Date().toISOString();

// =============================================
// NORMALIZE BRAZILIAN MOBILE NUMBERS
// WhatsApp format: 55 + DDD(2) + 8 digits = 12 chars
// GHL format:      55 + DDD(2) + 9 + 8 digits = 13 chars
// =============================================
let phoneGHL = phone;
if (phone.startsWith('55') && phone.length === 12) {
  const ddd = phone.substring(2, 4);
  const number = phone.substring(4);
  phoneGHL = '55' + ddd + '9' + number;
}
phoneGHL = '+' + phoneGHL;

return [{ json: { phone, phoneGHL, chatId, humanName, pausedAt: now } }];

// Preparar pausa para human takeover
// ANTI-DUPLICATA: se já tem tag atendimento-humano, sinaliza skip
const busca = $('Buscar Contato Pausa').first().json;
const contact = busca.contact || {};
const currentTags = contact.tags || [];

// Se já está pausado, sinalizar skip (flow para aqui via IF)
if (currentTags.some(t => t.toLowerCase() === 'atendimento-humano')) {
  return [{ json: { action: 'skip', reason: 'já em atendimento humano' } }];
}

const phone = $('Extrair Phone Humano').first().json;
const pausedAt = new Date().toISOString();
const pausaHoras = '2';

const newTags = [...currentTags.filter(t => t.toLowerCase() !== 'atendimento-humano'), 'atendimento-humano'];

return [{
  json: {
    action: 'pause',
    contactId: contact.id,
    contactName: phone.phone || '',
    phone: phone.phone || '',
    pausedAt: pausedAt,
    pausaHoras: pausaHoras,
    tags: newTags,
    customFields: [
      { id: 'fpZ7kyuOGNInXZ2926fq', field_value: pausedAt },
      { id: 'q9e1RgsmdEpEgcxkrMXH', field_value: pausaHoras }
    ]
  }
}];

// Check if still paused, build reactivation payload
const contact = $json.contact || $json;
if (!contact || !contact.tags) return [];

// If tag already removed manually, skip
if (!contact.tags.includes('atendimento-humano')) return [];

// Build new tags
const newTags = contact.tags.filter(t => t !== 'atendimento-humano');
if (!newTags.includes('Em Atendimento IA')) {
  newTags.push('Em Atendimento IA');
}

return [{ json: {
  contactId: contact.id,
  tags: [...new Set(newTags)],
  customFields: [{ id: 'fpZ7kyuOGNInXZ2926fq', field_value: '' }]
} }];

// RACE CONDITION GUARD
// Re-checks GHL contact AFTER Clara finishes thinking
// If human entered during processing (tag added), ABORT sending
// IMPORTANT: Returns Clara SDR output, NOT the HTTP check output
const contact = $json.contact;
if (!contact) {
  // No contact found - new lead, proceed with Clara output
  return [{ json: $('Clara SDR').first().json }];
}

const BLOCK_TAGS = [
  'ia-pausada', 'atendimento-humano', 'nao-ia',
  'cliente-ativo', 'spam', 'bloqueado'
];
const tags = (contact.tags || []).map(t => t.toLowerCase().trim());
const blocked = BLOCK_TAGS.some(bt => tags.includes(bt));

if (blocked) {
  // Human entered during Clara processing - ABORT
  return [];
}

// All clear - forward Clara SDR output to Dividir Mensagens
return [{ json: $('Clara SDR').first().json }];

// Get image base64 - try multiple sources
const original = $('Extrair Dados').first().json;

// Source 1: Stevo webhook includes base64 in Message
const webhookData = $('Webhook Stevo').first().json;
const webhookBase64 = webhookData?.body?.data?.Message?.base64 || '';

// Source 2: Download node result (fallback)
let downloadBase64 = '';
try {
  const downloadResult = $('Baixar Imagem Stevo').first().json;
  downloadBase64 = downloadResult?.base64 || '';
} catch(e) { /* download may have failed */ }

// Use whichever source has data
const imageBase64 = webhookBase64 || downloadBase64;

if (!imageBase64) {
  return [{ json: { ...original, text: '[Imagem recebida - não foi possível processar]', hasImage: false } }];
}

// Get mimetype from imageMessage metadata
const imgMsg = webhookData?.body?.data?.Message?.imageMessage || {};
const mimetype = imgMsg.mimetype || 'image/jpeg';

return [{
  json: { ...original, imageBase64: imageBase64, hasImage: true },
  binary: {
    image: {
      data: imageBase64,
      mimeType: mimetype,
      fileName: 'image.' + (mimetype.split('/')[1] || 'jpg')
    }
  }
}];

// Check if message already exists in Supabase
const result = $input.first().json;
// HTTP Request splits array into items.
// - New msg: Supabase returns [] → alwaysOutputData gives {}
// - Duplicate: Supabase returns [{id:X}] → we get {id:X}
const isDuplicate = result && result.id !== undefined;
if (isDuplicate) {
  // Stop execution for duplicates
  return [];
}
// Pass through original Extrair Dados data for new messages
return [{ json: $("Extrair Dados").first().json }];

// Get document base64 from webhook data
const original = $('Extrair Dados').first().json;
const webhookData = $('Webhook Stevo').first().json;
const webhookBase64 = webhookData?.body?.data?.Message?.base64 || '';
const docMsg = webhookData?.body?.data?.Message?.documentMessage || {};
const fileName = docMsg.fileName || docMsg.title || 'documento';
const mimetype = docMsg.mimetype || 'application/pdf';
const isPdf = mimetype.includes('pdf') || fileName.toLowerCase().endsWith('.pdf');

if (!webhookBase64) {
  return [{ json: { ...original, text: '[Documento recebido: ' + fileName + ' - não foi possível processar]', hasDocument: false, fileName } }];
}

return [{
  json: { ...original, hasDocument: true, fileName, isPdf, mimetype },
  binary: {
    data: {
      data: webhookBase64,
      mimeType: mimetype,
      fileName: fileName
    }
  }
}];

const pdfOutput = $input.first().json;
let prepDoc = {};
try { prepDoc = $("Preparar Documento").first().json || {}; } catch(e) {}
const fileName = prepDoc.fileName || "documento";
const NL = String.fromCharCode(10);
let extractedText = String(pdfOutput.text || "");
const nPages = pdfOutput.numpages || 0;
extractedText = extractedText.replace(/[�-  -]/g, " ");
if (!extractedText || extractedText.trim().length < 50) {
  extractedText = "[PDF com " + nPages + " paginas - conteudo visual/imagens]";
}
if (extractedText.length > 3000) {
  extractedText = extractedText.substring(0, 3000) + NL + "... [truncado, " + extractedText.length + " chars total, " + nPages + " paginas]";
}
const header = "[Documento: " + fileName + " (" + nPages + " pgs)]";
const result = { text: header + NL + NL + extractedText, fileName: fileName, nPages: nPages, hasText: extractedText.length > 50 };
return [{ json: result }];
